/**
 * PhantomShell Terminal Component
 *
 * Real terminal emulator using xterm.js with full keyboard support,
 * command history, and visual styling matching the Neuman Brain theme.
 *
 * Features:
 * - Full ANSI color support
 * - Command history (up/down arrows)
 * - Copy/paste support
 * - Auto-resize on container change
 * - Clickable URLs
 * - Find functionality (Ctrl+Shift+F)
 */

import React, { useEffect, useRef } from 'react';
import { Terminal as XTerm } from '@xterm/xterm';
import { FitAddon } from '@xterm/addon-fit';
import { WebLinksAddon } from '@xterm/addon-web-links';
import { SearchAddon } from '@xterm/addon-search';
import '@xterm/xterm/css/xterm.css';
import { usePhantomShellStore } from '../../stores/usePhantomShellStore';
import { logger } from '../../services/logger';

const log = logger.module('PhantomShell:Terminal');

// Neuman Brain theme colors mapped to xterm
const THEME = {
  background: '#0a0a0f',           // Dark surface
  foreground: '#e4e4e7',           // Light text
  cursor: '#d946ef',               // Magenta accent
  cursorAccent: '#0a0a0f',
  selectionBackground: '#3b0764',  // Purple selection
  selectionForeground: '#e4e4e7',
  // ANSI colors
  black: '#18181b',
  red: '#ef4444',
  green: '#22c55e',
  yellow: '#eab308',
  blue: '#3b82f6',
  magenta: '#d946ef',              // Primary accent
  cyan: '#06b6d4',                 // Secondary accent
  white: '#e4e4e7',
  brightBlack: '#71717a',
  brightRed: '#f87171',
  brightGreen: '#4ade80',
  brightYellow: '#facc15',
  brightBlue: '#60a5fa',
  brightMagenta: '#e879f9',
  brightCyan: '#22d3ee',
  brightWhite: '#fafafa',
};

interface TerminalProps {
  onData?: (data: string) => void;
  onResize?: (cols: number, rows: number) => void;
}

export const Terminal: React.FC<TerminalProps> = ({ onData, onResize }) => {
  const terminalRef = useRef<HTMLDivElement>(null);
  const xtermRef = useRef<XTerm | null>(null);
  const fitAddonRef = useRef<FitAddon | null>(null);
  const isInitializedRef = useRef(false);

  // Store callbacks in refs to avoid re-initialization when they change
  const onDataRef = useRef(onData);
  const onResizeRef = useRef(onResize);

  // Keep refs updated
  useEffect(() => {
    onDataRef.current = onData;
    onResizeRef.current = onResize;
  }, [onData, onResize]);

  const setTerminalInstance = usePhantomShellStore((state) => state.setTerminalInstance);

  // Initialize terminal - runs once on mount
  useEffect(() => {
    // Guard against double initialization (React Strict Mode)
    if (!terminalRef.current || isInitializedRef.current) return;

    log.info('Initializing xterm.js terminal');
    isInitializedRef.current = true;

    const xterm = new XTerm({
      theme: THEME,
      fontFamily: '"JetBrains Mono", "Fira Code", "Cascadia Code", Menlo, monospace',
      fontSize: 14,
      lineHeight: 1.2,
      cursorBlink: true,
      cursorStyle: 'block',
      scrollback: 10000,
      tabStopWidth: 4,
      convertEol: true, // Convert \n to \r\n - critical for proper line handling
      allowProposedApi: true,
    });

    // Add fit addon for auto-resize
    const fitAddon = new FitAddon();
    xterm.loadAddon(fitAddon);
    fitAddonRef.current = fitAddon;

    // Add web links addon for clickable URLs
    const webLinksAddon = new WebLinksAddon();
    xterm.loadAddon(webLinksAddon);

    // Add search addon
    const searchAddon = new SearchAddon();
    xterm.loadAddon(searchAddon);

    // Open terminal in container
    xterm.open(terminalRef.current);
    fitAddon.fit();

    // Store reference
    xtermRef.current = xterm;
    setTerminalInstance(xterm);

    // Set up data handler - uses ref so it always calls latest callback
    xterm.onData((data) => {
      onDataRef.current?.(data);
    });

    // Set up resize handler - uses ref so it always calls latest callback
    xterm.onResize(({ cols, rows }) => {
      log.debug('Terminal resized', { cols, rows });
      onResizeRef.current?.(cols, rows);
    });

    // Initial welcome message (fits 30 cols)
    xterm.writeln('\x1b[1;35m╔════════════════════════════╗\x1b[0m');
    xterm.writeln('\x1b[1;35m║\x1b[0m   \x1b[1;36mPhantom Shell\x1b[0m          \x1b[1;35m║\x1b[0m');
    xterm.writeln('\x1b[1;35m║\x1b[0m   \x1b[90mBrowser Native Dev\x1b[0m     \x1b[1;35m║\x1b[0m');
    xterm.writeln('\x1b[1;35m╚════════════════════════════╝\x1b[0m');
    xterm.writeln('');
    xterm.writeln('\x1b[90mType \x1b[33m/help\x1b[90m for commands\x1b[0m');
    xterm.writeln('');

    log.info('Terminal initialized successfully');

    // Cleanup - only runs on unmount
    return () => {
      log.debug('Disposing terminal');
      xterm.dispose();
      xtermRef.current = null;
      fitAddonRef.current = null;
      isInitializedRef.current = false;
    };
  }, [setTerminalInstance]); // Only setTerminalInstance as dependency (stable from Zustand)

  // Handle container resize
  useEffect(() => {
    const handleResize = () => {
      if (fitAddonRef.current && xtermRef.current) {
        fitAddonRef.current.fit();
      }
    };

    const resizeObserver = new ResizeObserver(handleResize);
    if (terminalRef.current) {
      resizeObserver.observe(terminalRef.current);
    }

    window.addEventListener('resize', handleResize);

    return () => {
      resizeObserver.disconnect();
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return (
    <div className="w-full h-full min-h-[300px] bg-[#0a0a0f] rounded-lg overflow-hidden p-2">
      <div
        ref={terminalRef}
        className="w-full h-full"
      />
    </div>
  );
};

export default Terminal;

/**
 * Preview Pane Component
 *
 * Shows running dev server output in an iframe.
 * Displays when a dev server is running in WebContainer.
 */

import React, { useState } from 'react';
import { usePhantomShellStore } from '../../stores/usePhantomShellStore';

interface PreviewProps {
  className?: string;
}

export const Preview: React.FC<PreviewProps> = ({ className = '' }) => {
  const { devServerUrl, isDevServerRunning, showPreview } = usePhantomShellStore();
  const [isLoading, setIsLoading] = useState(true);

  if (!showPreview) return null;

  if (!isDevServerRunning || !devServerUrl) {
    return (
      <div className={`flex items-center justify-center bg-[#0a0a0f] ${className}`}>
        <div className="text-center text-neutral-400">
          <div className="text-4xl mb-4">🚀</div>
          <p className="text-sm">No dev server running</p>
          <p className="text-xs mt-2">
            Run <code className="text-fuchsia-500">npm run dev</code> to start
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className={`relative bg-white ${className}`}>
      {isLoading && (
        <div className="absolute inset-0 flex items-center justify-center bg-[#0a0a0f] z-10">
          <div className="flex flex-col items-center">
            <div className="animate-spin w-8 h-8 border-2 border-fuchsia-500 border-t-transparent rounded-full" />
            <p className="mt-4 text-sm text-neutral-400">Loading preview...</p>
          </div>
        </div>
      )}

      <iframe
        src={devServerUrl}
        className="w-full h-full border-0"
        onLoad={() => setIsLoading(false)}
        title="Preview"
        sandbox="allow-scripts allow-same-origin allow-forms allow-modals allow-popups"
      />

      {/* URL bar */}
      <div className="absolute top-0 left-0 right-0 bg-black/90 backdrop-blur-sm px-3 py-1.5 flex items-center gap-2 border-b border-neutral-800">
        <div className="w-2 h-2 rounded-full bg-green-500" />
        <span className="text-xs text-neutral-400 font-mono truncate flex-1">
          {devServerUrl}
        </span>
        <button
          onClick={() => window.open(devServerUrl, '_blank')}
          className="text-xs text-cyan-400 hover:underline"
        >
          Open ↗
        </button>
      </div>
    </div>
  );
};

export default Preview;

