     1→/**
     2→ * AI Terminal Component
     3→ * Persistent AI assistant with multi-provider chat interface
     4→ *
     5→ * Features:
     6→ * - Multiple AI providers (OpenRouter, Groq, HuggingFace, Mistral, Gemini, OpenAI, Anthropic, xAI)
     7→ * - Provider/model selection
     8→ * - Automatic fallback on errors
     9→ * - Usage tracking
    10→ * - Encrypted API key storage
    11→ */
    12→
    13→import React, { useState, useRef, useEffect, useCallback } from 'react';
    14→import { useTerminalStore } from '../stores/useTerminalStore';
    15→import { aiTerminalService } from '../services/aiTerminal';
    16→import { createDefaultRouter } from '../services/ai/providerRouter';
    17→import { ProviderSettings } from './ProviderSettings';
    18→import { ModelSelector } from './ModelSelector';
    19→import { UsageTracker } from './UsageTracker';
    20→import { Terminal as PhantomTerminal, Preview as PhantomPreview } from './PhantomShell';
    21→import { usePhantomShellStore } from '../stores/usePhantomShellStore';
    22→import { runCommand, createShellContext, setRouter as setAICommandRouter } from '../services/phantomShell';
    23→import ReactMarkdown from 'react-markdown';
    24→import rehypeSanitize, { defaultSchema } from 'rehype-sanitize';
    25→
    26→type TerminalMode = 'chat' | 'shell';
    27→
    28→/**
    29→ * Custom sanitization schema for AI-generated content
    30→ * Extends default schema to allow safe code elements while blocking dangerous ones
    31→ *
    32→ * Security: This prevents XSS attacks from malicious AI responses
    33→ */
    34→const sanitizeSchema = {
    35→  ...defaultSchema,
    36→  tagNames: [
    37→    // Text formatting
    38→    'p', 'br', 'strong', 'em', 'b', 'i', 'u', 's', 'del', 'ins', 'mark',
    39→    // Headings
    40→    'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
    41→    // Lists
    42→    'ul', 'ol', 'li',
    43→    // Code
    44→    'pre', 'code',
    45→    // Quotes & dividers
    46→    'blockquote', 'hr',
    47→    // Links (href will be sanitized)
    48→    'a',
    49→    // Tables
    50→    'table', 'thead', 'tbody', 'tr', 'th', 'td',
    51→    // Other safe elements
    52→    'span', 'div',
    53→  ],
    54→  attributes: {
    55→    ...defaultSchema.attributes,
    56→    a: ['href', 'title', 'target', 'rel'],
    57→    code: ['className'], // For syntax highlighting classes
    58→    pre: ['className'],
    59→    span: ['className'],
    60→    div: ['className'],
    61→  },
    62→  // Force safe link attributes
    63→  protocols: {
    64→    href: ['http', 'https', 'mailto'],
    65→  },
    66→};
    67→
    68→export const AITerminal: React.FC = () => {
    69→  const {
    70→    isOpen,
    71→    apiKey, // Legacy Gemini key
    72→    // model is legacy and unused - destructured but not assigned to avoid TS error
    73→    activeProvider,
    74→    activeModel,
    75→    providers,
    76→    encryptionPassword,
    77→    isPasswordExpired,
    78→    fallbackEnabled,
    79→    messages,
    80→    isStreaming,
    81→    setOpen,
    82→    setActiveProvider,
    83→    addMessage,
    84→    clearMessages,
    85→    setStreaming,
    86→  } = useTerminalStore();
    87→
    88→  const [input, setInput] = useState('');
    89→  const [streamingContent, setStreamingContent] = useState('');
    90→  const [showProviderSettings, setShowProviderSettings] = useState(false);
    91→  const [showModelSelector, setShowModelSelector] = useState(false);
    92→  const [showUsageTracker, setShowUsageTracker] = useState(false);
    93→  const [fallbackNotification, setFallbackNotification] = useState<string | null>(null);
    94→  const [terminalMode, setTerminalMode] = useState<TerminalMode>('chat');
    95→
    96→  // Phantom Shell state
    97→  const phantomStore = usePhantomShellStore();
    98→  const [shellInput, setShellInput] = useState('');
    99→
   100→  const messagesEndRef = useRef<HTMLDivElement>(null);
   101→  const inputRef = useRef<HTMLTextAreaElement>(null);
   102→  const fallbackTimeoutRef = useRef<NodeJS.Timeout | null>(null);
   103→
   104→  // Initialize provider router
   105→  const [router] = useState(() => createDefaultRouter((failedProvider, _failedModel, nextProvider, nextModel, reason) => {
   106→    // Fallback notification callback
   107→    setFallbackNotification(
   108→      `⚠️ ${failedProvider} failed: ${reason}. Switched to ${nextProvider} (${nextModel}).`
   109→    );
   110→    // Clear any existing timeout to prevent memory leaks
   111→    if (fallbackTimeoutRef.current) {
   112→      clearTimeout(fallbackTimeoutRef.current);
   113→    }
   114→    fallbackTimeoutRef.current = setTimeout(() => setFallbackNotification(null), 5000);
   115→  }));
   116→
   117→  // Share router with AI command service (Phantom Shell)
   118→  useEffect(() => {
   119→    setAICommandRouter(router);
   120→  }, [router]);
   121→
   122→  // Cleanup timeout on unmount
   123→  useEffect(() => {
   124→    return () => {
   125→      if (fallbackTimeoutRef.current) {
   126→        clearTimeout(fallbackTimeoutRef.current);
   127→      }
   128→    };
   129→  }, []);
   130→
   131→  // Auto-scroll to bottom when messages change
   132→  useEffect(() => {
   133→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   134→  }, [messages, streamingContent]);
   135→
   136→  // Focus input when terminal opens
   137→  useEffect(() => {
   138→    if (isOpen) {
   139→      inputRef.current?.focus();
   140→    }
   141→  }, [isOpen]);
   142→
   143→  // Initialize AI service with API key (legacy Gemini)
   144→  useEffect(() => {
   145→    if (apiKey) {
   146→      aiTerminalService.setApiKey(apiKey);
   147→    }
   148→  }, [apiKey]);
   149→
   150→  // Configure router with active provider and model
   151→  useEffect(() => {
   152→    router.updateConfig({
   153→      primaryProvider: activeProvider,
   154→      primaryModel: activeModel,
   155→      fallbackEnabled: fallbackEnabled,
   156→    });
   157→  }, [activeProvider, activeModel, fallbackEnabled, router]);
   158→
   159→  // Initialize provider API keys from encrypted storage
   160→  useEffect(() => {
   161→    const initializeApiKeys = async () => {
   162→      if (encryptionPassword && !isPasswordExpired()) {
   163→        const allProviders = router.getAllProviders();
   164→        for (const [providerId, provider] of Object.entries(allProviders)) {
   165→          const providerConfig = providers[providerId];
   166→          if (providerConfig && providerConfig.encryptedApiKey) {
   167→            try {
   168→              const decryptedKey = await useTerminalStore.getState().getProviderApiKey(providerId, encryptionPassword);
   169→              if (decryptedKey) {
   170→                provider.setApiKey(decryptedKey);
   171→              }
   172→            } catch (error) {
   173→              console.error(`Failed to decrypt ${providerId} API key:`, error);
   174→            }
   175→          }
   176→        }
   177→      }
   178→    };
   179→
   180→    initializeApiKeys();
