   699→          </div>
   700→        </div>
   701→      )}
   702→
   703→      {/* Usage Tracker Sliding Panel */}
   704→      {showUsageTracker && (
   705→        <div className="absolute top-12 right-0 w-80 max-h-[70vh] bg-white dark:bg-surface-dark-elevated border-l border-border-light dark:border-border-dark shadow-xl overflow-hidden flex flex-col">
   706→          <div className="p-3 border-b border-border-light dark:border-border-dark flex items-center justify-between bg-surface-light dark:bg-surface-dark flex-shrink-0">
   707→            <h3 className="font-semibold text-sm text-text-light-primary dark:text-text-dark-primary">
   708→              Usage Tracker
   709→            </h3>
   710→            <button
   711→              onClick={() => setShowUsageTracker(false)}
   712→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-neutral-800 rounded-button"
   713→            >
   714→              ✕
   715→            </button>
   716→          </div>
   717→          <div className="p-3 overflow-y-auto flex-1">
   718→            <UsageTracker router={router} />
   719→          </div>
   720→        </div>
   721→      )}
