   271→      process.output.pipeTo(new WritableStream({
   272→        write(data) {
   273→          onStdout(data);
   274→        }
   275→      })).catch((err) => {
   276→        // Stream might be cancelled on kill
   277→        if (err?.name !== 'AbortError') {
   278→          log.error('Output stream error', { error: err });
   279→        }
   280→      });
   281→
   282→      // Wait for exit
   283→      const exitCode = await process.exit;
   284→      this.currentProcess = null;
   285→
   286→      log.debug('Command completed', { command: command.name, exitCode });
   287→      return exitCode;
   288→    } catch (error) {
   289→      log.error('Command execution failed', { command: command.raw, error });
   290→      onStderr(`\x1b[31mError: ${error}\x1b[0m\n`);
   291→      this.currentProcess = null;
   292→      return 1;
   293→    }
   294→  }
   295→
   296→  async executeAI(
   297→    command: ShellCommand,
   298→    onOutput: (data: string) => void,
   299→  ): Promise<number> {
   300→    const prompt = command.args.join(' ');
   301→    log.info('AI command', { prompt: prompt.substring(0, 100) });
   302→
   303→    // Show thinking indicator
   304→    onOutput('\x1b[36m⏳ Thinking...\x1b[0m\n');
   305→
   306→    try {
   307→      const result = await processAICommand(prompt);
   308→
   309→      // Clear thinking indicator (move up and clear line)
   310→      onOutput('\x1b[1A\x1b[2K');
   311→
   312→      // Handle error
   313→      if (result.error) {
   314→        onOutput(`\x1b[31m${result.error}\x1b[0m\n`);
   315→        return 1;
   316→      }
   317→
   318→      // Show explanation if present
   319→      if (result.explanation) {
   320→        onOutput(`\x1b[90m${result.explanation}\x1b[0m\n`);
   321→      }
   322→
   323→      // Show commands
   324→      if (result.commands.length === 0) {
   325→        onOutput('\x1b[33mNo commands generated.\x1b[0m\n');
   326→        return 0;
   327→      }
   328→
   329→      // Display generated commands
   330→      onOutput('\x1b[32m📋 Generated commands:\x1b[0m\n');
   331→      for (const cmd of result.commands) {
   332→        onOutput(`  \x1b[36m$ ${cmd}\x1b[0m\n`);
   333→      }
   334→      onOutput('\n');
   335→
   336→      // Ask user to confirm (for now, just show them)
   337→      onOutput('\x1b[90mCopy and paste to execute,\x1b[0m\n');
   338→      onOutput('\x1b[90mor type the command manually.\x1b[0m\n');
   339→
   340→      return 0;
   341→    } catch (error) {
   342→      log.error('AI command execution failed', { error });
   343→      onOutput('\x1b[1A\x1b[2K'); // Clear thinking indicator
   344→      onOutput(`\x1b[31mAI Error: ${error}\x1b[0m\n`);
   345→      return 1;
   346→    }
   347→  }
   348→
   349→  kill() {
   350→    if (this.currentProcess) {
   351→      log.info('Killing current process');
   352→      this.currentProcess.kill();
   353→      this.currentProcess = null;
   354→    } else {
   355→      log.debug('Kill requested (no active process)');
   356→    }
   357→  }
   358→}
   359→
   360→export const shellExecutor = new ShellExecutor();
   361→
   362→// ==================== SHELL RUNNER ====================
   363→
   364→/**
   365→ * Main entry point for running commands
   366→ */
   367→export const runCommand = async (
   368→  input: string,
   369→  context: ShellContext,
   370→  onOutput: (data: string) => void,
   371→): Promise<number> => {
   372→  const command = parseCommand(input);
   373→
   374→  log.debug('Running command', { type: command.type, name: command.name });
   375→
   376→  switch (command.type) {
   377→    case 'builtin': {
   378→      const result = await shellExecutor.executeBuiltin(command, context);
   379→      if (result) {
   380→        onOutput(result + '\n');
   381→      }
   382→      return 0;
   383→    }
   384→
   385→    case 'ai': {
   386→      return shellExecutor.executeAI(command, onOutput);
   387→    }
   388→
   389→    case 'system': {
   390→      return shellExecutor.executeSystem(command, onOutput, onOutput);
   391→    }
   392→
   393→    default:
   394→      onOutput('\x1b[31mUnknown command type\x1b[0m\n');
   395→      return 1;
   396→  }
   397→};
   398→
   399→// ==================== UTILITIES ====================
   400→
   401→/**
   402→ * Create a shell context from store state
   403→ */
   404→export const createShellContext = (
   405→  terminal: ShellContext['terminal'],
   406→  store: {
   407→    activeProjectId: string | null;
   408→    commandHistory: { command: string; timestamp: string }[];
   409→    projects: Record<string, PhantomProject>;
   410→    createProject: (project: Omit<PhantomProject, 'id' | 'createdAt' | 'updatedAt'>) => string;
   411→  }
   412→): ShellContext => ({
   413→  terminal,
   414→  activeProjectId: store.activeProjectId,
   415→  getHistory: () => store.commandHistory,
   416→  getProjects: () => Object.values(store.projects).map(p => ({
   417→    id: p.id,
   418→    name: p.name,
   419→    metadata: p.metadata,
   420→  })),
   421→  createProject: (name: string) => store.createProject({
   422→    name,
   423→    files: {},
   424→    metadata: {},
   425→  }),
   426→});
   427→

