     2→ * AI Terminal Service
     3→ * Handles communication with Google Gemini API
     4→ */
     5→
     6→import { GoogleGenerativeAI, type Content } from '@google/generative-ai';
     7→import type { Message } from '../stores/useTerminalStore';
     8→
     9→const SYSTEM_PROMPT = `You are an AI assistant integrated into Neuman Brain, a productivity web application. You help users with:
    10→
    11→1. **General Questions**: Answer questions on any topic
    12→2. **Code Generation**: Generate React/TypeScript/JavaScript code snippets
    13→3. **Code Explanation**: Explain code and debug errors
    14→4. **Terminal Commands**: Explain shell commands and their usage
    15→5. **Productivity**: Help with task management, planning, note-taking
    16→
    17→**Guidelines:**
    18→- Be concise and helpful
    19→- Format code with markdown code blocks
    20→- For complex code, explain what it does
    21→- If user asks for terminal commands, explain them clearly
    22→- Always consider the context of a web-based productivity app
    23→
    24→**Current Context:**
    25→- App: Neuman Brain (React + TypeScript + Tailwind CSS)
    26→- Features: Dashboard widgets, Tasks (Kanban), Calendar, Notes, Planning
    27→- Storage: IndexedDB (local-first, privacy-focused)
    28→`;
    29→
    30→export class AITerminalService {
    31→  private genAI: GoogleGenerativeAI | null = null;
    32→  private apiKey: string | null = null;
    33→
    34→  setApiKey(key: string) {
    35→    this.apiKey = key;
    36→    this.genAI = new GoogleGenerativeAI(key);
    37→  }
    38→
    39→  isConfigured(): boolean {
    40→    return !!this.apiKey && !!this.genAI;
    41→  }
    42→
    43→  /**
    44→   * Convert our Message format to Gemini's Content format
    45→   */
    46→  private messagesToHistory(messages: Message[]): Content[] {
    47→    return messages
    48→      .filter((msg) => msg.role !== 'system')
    49→      .map((msg) => ({
    50→        role: msg.role === 'assistant' ? 'model' : 'user',
    51→        parts: [{ text: msg.content }],
    52→      }));
    53→  }
    54→
    55→  /**
    56→   * Send a message and get a response
    57→   */
    58→  async sendMessage(
    59→    userMessage: string,
    60→    chatHistory: Message[],
    61→    model: 'gemini-1.5-flash' | 'gemini-1.5-pro' = 'gemini-1.5-flash',
    62→    onChunk?: (text: string) => void
    63→  ): Promise<string> {
    64→    if (!this.genAI) {
    65→      throw new Error('API key not configured. Please add your Google AI API key in Settings.');
    66→    }
    67→
    68→    try {
    69→      const genModel = this.genAI.getGenerativeModel({ model });
    70→
    71→      // Convert chat history to Gemini format
    72→      const history = this.messagesToHistory(chatHistory);
    73→
    74→      // Start chat with history
    75→      const chat = genModel.startChat({
    76→        history,
    77→        generationConfig: {
    78→          maxOutputTokens: 2048,
    79→          temperature: 0.7,
    80→        },
    81→        systemInstruction: SYSTEM_PROMPT,
